// show_metadata.c - قراءة metadata النصية من ملف وسائط
#include <libavformat/avformat.h>
#include <stdio.h>
#include <string.h>

static void print_metadata(const char *key, const char *value) {
    if (value && value[0]) {
        printf("  %s: %s\n", key, value);
    }
}

int main(int argc, char **argv) {
    const char *filename = argc > 1 ? argv[1] : "input.mp3";
    AVFormatContext *fmt_ctx = NULL;

    avformat_open_input(&fmt_ctx, filename, NULL, NULL);
n    avformat_find_stream_info(fmt_ctx, NULL);

    // طباعة metadata على مستوى الحاوي
    print_metadata("title", fmt_ctx->metadata->title);
    print_metadata("artist", fmt_ctx->metadata->artist);
    print_metadata("album", fmt_ctx->metadata->album);
    print_metadata("genre", fmt_ctx->metadata->genre);
    print_metadata("date", fmt_ctx->metadata->date);
    print_metadata("track", fmt_ctx->metadata->track);

    // طباعة metadata لكل stream
    for (unsigned i = 0; i < fmt_ctx->nb_streams; i++) {
        AVDictionaryEntry *tag = NULL;
n        while ((tag = av_dict_iter(fmt_ctx->metadata, &tag)) != NULL) {
            printf("  [%d] %s: %s\n", i, tag->key, tag->value);
        }
    }

    avformat_close_input(&fmt_ctx);
    return 0;
}

